import React, { useState, useRef } from "react";
import MapView from "../components/MapView";
import CameraCapture from "../components/CameraCapture";

function Journey() {

  const [originCoords, setOriginCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [vehicleImage, setVehicleImage] = useState(null);
  const [destination, setDestination] = useState("");
  const [journeyStarted, setJourneyStarted] = useState(false);
  const [safetyStatus, setSafetyStatus] = useState("SAFE");
  const [info, setInfo] = useState(null);
  const [tracking, setTracking] = useState(false);

  const watchId = useRef(null);

  const handleCapture = (img) => setVehicleImage(img);

  const triggerEmergency = () => {
    alert("🚨 Emergency triggered!");
    window.location.href = "tel:112";
  };

  const startTracking = () => {
    if (!navigator.geolocation) return alert("Enable GPS");

    setTracking(true);

    watchId.current = navigator.geolocation.watchPosition((pos) => {
      const lat = pos.coords.latitude;
      const lon = pos.coords.longitude;

      setOriginCoords({ lat, lon });
    });
  };

  const stopTracking = () => {
    navigator.geolocation.clearWatch(watchId.current);
    setTracking(false);
  };

  const setDestinationFunc = async () => {
    if (!destination) return alert("Enter destination");

    const res = await fetch(
      `https://nominatim.openstreetmap.org/search?format=json&q=${destination}`
    );

    const data = await res.json();

    if (data.length > 0) {
      setDestinationCoords({
        lat: parseFloat(data[0].lat),
        lon: parseFloat(data[0].lon),
      });
      setJourneyStarted(true);
    } else {
      alert("Location not found");
    }
  };

  return (
    <div className="journey-page">

      {/* 🔥 TOP STATUS BAR */}
      <div className={`status-bar ${safetyStatus}`}>
        <span className="pulse"></span>
        {safetyStatus === "SAFE" ? "Safe Journey" : "Emergency Mode"}
      </div>

      {/* 🎯 MAIN CONTROL CARD */}
      <div className="journey-card">

        <h2>🚗 Start Your Journey</h2>

        <div className="input-group">
          <input
            type="text"
            placeholder="Enter destination..."
            value={destination}
            onChange={(e) => setDestination(e.target.value)}
            disabled={journeyStarted}
          />

          <button onClick={setDestinationFunc}>
            📍 Set
          </button>
        </div>

        {/* ACTION BUTTONS */}
        <div className="action-row">

          <button
            className="start-btn"
            onClick={startTracking}
            disabled={tracking}
          >
            {tracking ? "Tracking..." : "▶ Start"}
          </button>

          <button className="stop-btn" onClick={stopTracking}>
            ⏹ Stop
          </button>

        </div>

        {/* INFO */}
        {info && (
          <div className="info-box">
            <p>📏 {info.distance} km</p>
            <p>⏱ {info.time} mins</p>
          </div>
        )}

        {/* CAMERA */}
        <CameraCapture onCapture={handleCapture} />

        {vehicleImage && (
          <div className="image-preview">
            <img src={vehicleImage} alt="vehicle" />
          </div>
        )}

      </div>

      {/* 🗺 MAP */}
      <div className="map-section">
        <MapView
          origin={originCoords}
          destination={destinationCoords}
          setInfo={setInfo}
        />
      </div>

      {/* 🚨 FLOATING SOS BUTTON */}
      <button className="floating-sos" onClick={triggerEmergency}>
        🚨
      </button>

    </div>
  );
}

export default Journey;
